<template>
  <h1>Что здесь происходит?</h1>
  <section v-if="about.length > 0" class="news">
    <useArticle :article="elem" v-for="elem in about" :key="elem.id"></useArticle>
  </section>
  <h3 v-else>Загружаем...</h3>
</template>

<script>
import supabase from '@/api/supabase';
import useArticle from './useArticle.vue';
export default {
    name: 'useAboutPage',
    components: {
      useArticle
    },
    data() {
      return {
        about: []
      }
    },
    mounted() {
      this.getAbout()
    },
    methods: {
      async getAbout() {
        const { data } = await supabase.from("news").select().limit(1).eq("type", "about")
        this.about.push(...data)
      }
    }
}
</script>

